from pyspark.sql import functions as F

def clean_str(col_expr):
    return (
        F.when(
            col_expr.isNull() |
            (F.trim(col_expr) == "") |
            (F.lower(F.trim(col_expr)) == "undefined"),
            F.lit(None)
        ).otherwise(F.trim(col_expr))

